mapper.update:
UPDATE t_oa_enterprise
SET deleted_flag = #{deletedFlag}
WHERE enterprise_id = #{enterpriseId}

mapper.select:
SELECT *
FROM t_oa_enterprise
WHERE enterprise_name = #{enterpriseName}
AND deleted_flag = #{deletedFlag}

    AND enterprise_id != #{excludeEnterpriseId}

SELECT oe.*
FROM t_oa_enterprise oe

    oe.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(oe.enterprise_name,#{queryForm.keywords}) OR INSTR(oe.contact,#{queryForm.keywords}) OR
        INSTR(oe.contact_phone,#{queryForm.keywords}) OR INSTR(oe.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(oe.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(oe.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND oe.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY oe.create_time DESC

SELECT enterprise_id, enterprise_name
FROM t_oa_enterprise
WHERE disabled_flag = #{disabledFlag}
AND deleted_flag = #{deletedFlag}

    AND type = #{type}

SELECT enterprise_id, enterprise_name
FROM t_oa_enterprise
WHERE disabled_flag = #{disabledFlag}
AND deleted_flag = #{deletedFlag}
AND type = #{type}

SELECT enterprise_id, enterprise_name
FROM t_oa_enterprise
WHERE disabled_flag = #{disabledFlag}
AND deleted_flag = #{deletedFlag}

    AND enterprise_id in

        #{item}

SELECT oe.*
FROM t_oa_enterprise oe
WHERE oe.enterprise_id = #{enterpriseId} AND oe.deleted_flag = #{deletedFlag}

SELECT *
FROM t_oa_enterprise
WHERE enterprise_name in

    #{item}

AND deleted_flag = #{deletedFlag}
